mapper.select:
SELECT id, chapter_id AS chapterId, video_name AS videoName, video_url AS videoUrl, cover_image AS coverImage, duration, file_size AS fileSize, video_format AS videoFormat, resolution, playback_type AS playbackType, master_playlist_url AS masterPlaylistUrl, renditions, default_resolution AS defaultResolution, sort_order AS sortOrder, status, view_count AS viewCount, created_time AS createdTime, updated_time AS updatedTime FROM course_video
AND chapter_id = #{q.chapterId}
AND video_name LIKE CONCAT('%', #{q.videoName}, '%')
AND video_format = #{q.videoFormat}
AND status = #{q.status}
AND created_time BETWEEN #{q.beginTime} AND #{q.endTime}
ORDER BY sort_order ASC, created_time DESC

